fn route_request(req: &Request) -> &'static str {
    let path = req.get_path();

    if path.starts_with("/api/") || path.starts_with("/v1/") || path.starts_with("/v2/") {
        BACKEND_API
    } else if path.starts_with("/static/")
        || path.starts_with("/assets/")
        || path.starts_with("/images/")
        || path.starts_with("/css/")
        || path.starts_with("/js/")
    {
        BACKEND_STATIC
    } else if path.starts_with("/auth/")
        || path.starts_with("/login")
        || path.starts_with("/logout")
        || path.starts_with("/oauth/")
    {
        BACKEND_AUTH
    } else {
        BACKEND_DEFAULT
    }
}

fn get_backend_config(backend_name: &str) -> Option<BackendConfig> {
    get_backend_configs()
        .into_iter()
        .find(|config| config.name == backend_name)
}

fn add_request_headers(req: &mut Request, config: &BackendConfig) {
    req.set_header("X-Forwarded-Proto", if config.use_tls { "https" } else { "http" });
    req.set_header("X-Backend-Name", config.name);
    req.set_header(header::HOST, config.host);

    if !req.contains_header("X-Request-Id") {
        let request_id = format!("{:x}", fastly::handle::RequestHandle::from(req).as_u32());
        req.set_header("X-Request-Id", &request_id);
    }
}

fn handle_health_check() -> Response {
    Response::from_status(StatusCode::OK)
        .with_content_type(mime::APPLICATION_JSON)
        .with_body(r#"{"status": "healthy", "service": "edge-router"}"#)
}

fn handle_not_found() -> Response {
    Response::from_status(StatusCode::NOT_FOUND)
        .with_content_type(mime::APPLICATION_JSON)
        .with_body(r#"{"error": "not_found", "message": "The requested resource was not found"}"#)
}

fn handle_method_not_allowed() -> Response {
    Response::from_status(StatusCode::METHOD_NOT_ALLOWED)
        .with_content_type(mime::APPLICATION_JSON)
        .with_body(r#"{"error": "method_not_allowed", "message": "The request method is not allowed"}"#)
}

fn handle_bad_gateway(backend_name: &str, error: &str) -> Response {
    let body = format!(
        r#"{{"error": "bad_gateway", "message": "Failed to connect to backend", "backend": "{}", "details": "{}"}}"#,
        backend_name, error
    );
    Response::from_status(StatusCode::BAD_GATEWAY)
        .with_content_type(mime::APPLICATION_JSON)
        .with_body(body)
}

fn send_to_backend(mut req: Request, backend_name: &str) -> Result<Response, Error> {
    let config = match get_backend_config(backend_name) {
        Some(c) => c,
        None => {
            return Ok(handle_bad_gateway(
                backend_name,
                "Backend configuration not found",
            ));
        }
    };

    add_request_headers(&mut req, &config);

    let backend = Backend::from_name(config.name)?;

    match req.send(backend) {
        Ok(mut resp) => {
            resp.set_header("X-Served-By", config.name);
            resp.set_header("X-Backend-Host", config.host);
            Ok(resp)
        }
        Err(e) => {
            eprintln!(
                "Error sending request to backend {}: {}",
                backend_name, e
            );
            Ok(handle_bad_gateway(backend_name, &e.to_string()))
        }
    }
}

fn apply_security_headers(resp: &mut Response) {
    resp.set_header("X-Content-Type-Options", "nosniff");
    resp.set_header("X-Frame-Options", "DENY");
    resp.set_header("X-XSS-Protection", "1; mode=block");
    resp.set_header("Referrer-Policy", "strict-origin-when-cross-origin");
    resp.set_header(
        "Strict-Transport-Security",
        "max-age=31536000; includeSubDomains; preload",
    );
}

fn handle_cors_preflight(req: &Request) -> Option<Response> {
    if req.get_method() == Method::OPTIONS {
        let mut resp = Response::from_status(StatusCode::NO_CONTENT);
        resp.set_header("Access-Control-Allow-Origin", "*");
        resp.set_header(
            "Access-Control-Allow-Methods",
            "GET, POST, PUT, DELETE, PATCH, OPTIONS",
        );
        resp.set_header(
            "Access-Control-Allow-Headers",
            "Content-Type, Authorization, X-Request-Id",
        );
        resp.set_header("Access-Control-Max-Age", "86400");
        Some(resp)
    } else {
        None
    }
}

#[fastly::main]
fn main(req: Request) -> Result<Response, Error> {
    let path = req.get_path().to_owned();

    // Health check endpoint
    if path == "/health" || path == "/healthz" {
        return Ok(handle_health_check());
    }

    // Handle CORS preflight requests
    if let Some(cors_resp) = handle_cors_preflight(&req) {
        return Ok(cors_resp);
    }

    // Validate allowed methods
    match req.get_method() {
        &Method::GET
        | &Method::POST
        | &Method::PUT
        | &Method::DELETE
        | &Method::PATCH
        | &Method::HEAD => {}
        _ => return Ok(handle_method_not_allowed()),
    }

    // Determine the backend based on the request path
    let backend_name = route_request(&req);

    println!(
        "Routing request: {} {} -> backend: {}",
        req.get_method(),
        path,
        backend_name
    );

    // Send the request to the appropriate backend
    let mut resp = send_to_backend(req, backend_name)?;

    // Apply security headers to the response
    apply_security_headers(&mut resp);

    // Add CORS headers
    resp.set_header("Access-Control-Allow-Origin", "*");

    Ok(resp)
}